import { createClient } from '@/utils/supabase/server'
import Link from 'next/link'
import { LayoutDashboard, Folders, UserCircle, MessageSquare, LogOut, Settings } from 'lucide-react'

export default async function AdminDashboard() {
  const supabase = await createClient()
  
  // Ambil beberapa data statistik sederhana
  const { count: projectCount } = await supabase.from('Project').select('*', { count: 'exact', head: true })
  const { count: messageCount } = await supabase.from('Message').select('*', { count: 'exact', head: true })

  const menuItems = [
    { name: 'Dashboard', icon: <LayoutDashboard size={20} />, href: '/admin', active: true },
    { name: 'Profil', icon: <UserCircle size={20} />, href: '/admin/profile' },
    { name: 'Proyek', icon: <Folders size={20} />, href: '/admin/projects' },
    { name: 'Pesan', icon: <MessageSquare size={20} />, href: '/admin/messages' },
    { name: 'Pengaturan', icon: <Settings size={20} />, href: '/admin/settings' },
  ]

  return (
    <div className="min-h-screen bg-[#050505] text-white flex font-jakarta">
      {/* Sidebar */}
      <aside className="w-64 border-r border-white/5 bg-black/50 backdrop-blur-xl p-6 hidden md:block">
        <div className="mb-10">
          <Link href="/" className="text-xl font-bold font-outfit tracking-tighter">
            RIDHO<span className="text-teal-500">ADMIN.</span>
          </Link>
        </div>

        <nav className="space-y-2">
          {menuItems.map((item) => (
            <Link 
              key={item.name} 
              href={item.href}
              className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
                item.active ? 'bg-teal-500 text-black font-bold' : 'text-gray-400 hover:bg-white/5 hover:text-white'
              }`}
            >
              {item.icon}
              {item.name}
            </Link>
          ))}
        </nav>

        <div className="mt-auto pt-10">
          <button className="flex items-center gap-3 px-4 py-3 text-red-400 hover:bg-red-500/10 rounded-xl w-full transition-all">
            <LogOut size={20} />
            Keluar
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-8 overflow-y-auto">
        <header className="flex justify-between items-center mb-10">
          <h1 className="text-2xl font-bold">Dashboard Overview</h1>
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 rounded-full bg-teal-500 flex items-center justify-center font-bold text-black">
              R
            </div>
            <div>
              <p className="text-sm font-bold">Ridho Robbi Pasi</p>
              <p className="text-xs text-gray-500">Administrator</p>
            </div>
          </div>
        </header>

        {/* Stats Grid */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-10">
          {[
            { label: 'Total Proyek', value: projectCount || 0, color: 'text-teal-400' },
            { label: 'Pesan Baru', value: messageCount || 0, color: 'text-purple-400' },
            { label: 'Total Kunjungan', value: '1,234', color: 'text-blue-400' },
          ].map((stat) => (
            <div key={stat.label} className="p-6 bg-white/5 border border-white/10 rounded-3xl">
              <p className="text-gray-500 text-sm mb-2">{stat.label}</p>
              <p className={`text-4xl font-black ${stat.color}`}>{stat.value}</p>
            </div>
          ))}
        </div>

        {/* Recent Activity / Welcome */}
        <div className="p-10 bg-gradient-to-br from-teal-500/10 to-purple-500/10 border border-white/10 rounded-3xl relative overflow-hidden">
          <div className="relative z-10">
            <h2 className="text-3xl font-bold mb-4">Selamat Datang Kembali!</h2>
            <p className="text-gray-400 max-w-md">
              Panel admin sudah aktif. Anda bisa mulai mengelola konten portofolio Anda menggunakan database Supabase yang super cepat.
            </p>
            <button className="mt-8 px-6 py-3 bg-white text-black font-bold rounded-xl hover:scale-105 transition-all">
              Update Profil Sekarang
            </button>
          </div>
          {/* Abstract Shape */}
          <div className="absolute top-0 right-0 w-64 h-64 bg-teal-500/20 blur-[100px] rounded-full -mr-20 -mt-20"></div>
        </div>
      </main>
    </div>
  )
}
